solution_code:
#include <iostream>
#include <memory>

int main() {
    int n;
    std::cin >> n;

    std::unique_ptr<int> a = std::make_unique<int>(n);
    std::cout << "Created: " << *a << "\n";

    std::unique_ptr<int> b = std::move(a);
    std::cout << "After first move: " << *b << "\n";

    std::unique_ptr<int> c = std::move(b);
    std::cout << "After second move: " << *c << "\n";

    return 0;
}

